#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e6+5;
const LL MOD = 1e9+7;
LL n,p[N],cnt,Ans;bool vis[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Sol_prime(LL prime){
    LL x=prime,cnt=0;
    while(x<=n)cnt+=n/x,x*=prime;
    Ans=Ans*(2*cnt+1)%MOD;return;
}
int main(){
    n=read();Ans=1;
    vis[0]=1,vis[1]=1;
    for(LL i=2;i<=n;i++){
        if(vis[i])continue;p[++cnt]=i;
        for(LL j=i*i;j<=n;j+=i)vis[j]=1;
    }for(int i=1;i<=cnt;i++)
        Sol_prime(p[i]);cout<<Ans<<"\n";
    return 0;
}
